package com.pos;
import javax.swing.*;import java.awt.*;
public class UserLoyaltyPanel extends JPanel {public UserLoyaltyPanel(UserSession s){super(new BorderLayout(8,8));QueryTableModel m=new QueryTableModel();JTable t=new JTable(m);JPanel h=new JPanel(new BorderLayout());h.add(UIUtils.title("My Loyalty Points and Gift Cards"),BorderLayout.WEST);JButton b=new JButton("Refresh");h.add(b,BorderLayout.EAST);add(h,BorderLayout.NORTH);add(new JScrollPane(t),BorderLayout.CENTER);Runnable load=()->{try{m.load("SELECT 'POINTS' type,cp.loyalty_number reference,cp.loyalty_points value,cp.status FROM customer_profiles cp WHERE cp.user_id=? UNION ALL SELECT 'GIFT_CARD',g.gift_card_code,g.remaining_amount,g.status FROM gift_cards g JOIN customer_profiles cp ON cp.customer_id=g.customer_id WHERE cp.user_id=?",s.userId,s.userId);}catch(Exception e){UIUtils.error(this,e);}};b.addActionListener(e->load.run());load.run();}}
